
const { BrowserWindow } = require('electron');
const fs = require('fs');
const os = require('os');
const path = require('path');

const OSHINI_LOGO_B64 = ''
/**
 * Generates receipt HTML matching the DisplayHub.lk style receipt exactly,
 * but branded for Oshini Mobile.
 */
function buildReceiptHTML(invoice, shopConfig) {
  const shop = shopConfig || {};
  // Currency formatter with thousand separators, two decimals
  const currencyFormatter = new Intl.NumberFormat('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  const fmt = (n) => currencyFormatter.format(parseFloat(n || 0));

  // Treat both supplier_return and customer_return as "return" invoices for display rules
  const isReturnInvoice = invoice?.transaction_type === 'supplier_return' || invoice?.transaction_type === 'customer_return';
  // For customer returns prefer remaining_warranty field if present; otherwise fall back to item.warranty
  const warrantyText = (invoice.transaction_type === 'customer_return')
    ? ([...new Set((invoice.items || []).map((item) => (item.remaining_warranty || '').trim()).filter(Boolean))].join(', ') || '—')
    : (isReturnInvoice ? '' : ([...new Set((invoice.items || [])
      .map((item) => (item.warranty || '').trim())
      .filter(Boolean))].join(', ') || '—'));

  const itemRows = (invoice.items || []).map((item, i) => `
    <tr>
      <td class="item-name">${i + 1}) ${item.name || item.barcode}${item.barcode ? ' - ' + item.barcode : ''}</td>
    </tr>
    <tr>
      <td>
        <table class="item-detail-row">
            <tr>
            <td class="r">${fmt(item.price)}</td>
            ${isReturnInvoice ? '' : `<td class="r">${fmt(item.discount || 0)}</td><td class="r">${fmt(item.net_price)}</td>`}
            <td class="r">${item.quantity}.000</td>
            <td class="r">${fmt(item.total)}</td>
          </tr>
        </table>
      </td>
    </tr>
  `).join('');

  const shopName = shop.name || 'Oshini Mobile';
  const buildBarcodeSvg = (value) => {
    const code = String(value || '').replace(/[^0-9A-Za-z]/g, '').toUpperCase() || '000000';
    let width = 0;
    const bars = [];
    const barY = 2;
    const barHeight = 40;
    for (const ch of code) {
      const codePoint = ch.charCodeAt(0);
      const barWidth = 1 + (codePoint % 3);
      const gapWidth = 1 + (codePoint % 2);
      for (let i = 0; i < 3; i += 1) {
        bars.push(`<rect x="${width}" y="${barY}" width="${barWidth}" height="${barHeight}" fill="#000" />`);
        width += barWidth + gapWidth;
      }
      width += 2;
    }
    const viewWidth = Math.max(width, 120);
    return `<svg class="barcode-svg" viewBox="0 0 ${viewWidth} 44" preserveAspectRatio="none" xmlns="http://www.w3.org/2000/svg">${bars.join('')}</svg>`;
  };
  const shopTagline = shop.tagline || 'Smart Choice. Better Life';
  const shopAddr = shop.address || '';
  const shopPhone = shop.phone || '';

  const invoiceDate = invoice.created_at
    ? new Date(invoice.created_at).toLocaleString('en-GB').replace(',', '')
    : new Date().toLocaleString('en-GB').replace(',', '');

  const invoiceNo = invoice.invoice_no || '';
  const cashier   = invoice.cashier || shop.cashier || '';
  const customer  = invoice.customer_name || '';
  const custPhone = invoice.customer_phone || '';

  const balance = parseFloat(invoice.balance || 0);
  const balanceDisplay = balance > 0
    ? `[-${fmt(Math.abs(balance))}]`
    : `${fmt(balance)}`;

  const outstandingSection = balance !== 0 ? `
  <div class="divider"></div>
  <div class="bold center">Outstanding : ${fmt(Math.abs(balance))}</div>
  ` : '';

  return `<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8"/>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    font-family: Arial, Helvetica, sans-serif;
    font-size: 11px;
    font-weight: 500;
    line-height: 1.25;
    width: 72mm;
    padding: 4mm 3mm 8mm 3mm;
    color: #000;
    background: #fff;
    -webkit-print-color-adjust: exact;
    print-color-adjust: exact;
    text-rendering: geometricPrecision;
  }
  .center  { text-align: center; }
  .right   { text-align: right; }
  .bold    { font-weight: bold; }
  .receipt-header { text-align: center; margin-bottom: 3px; }
  .shop-name { font-size: 11px; font-weight: 700; letter-spacing: 0.1px; }
  .logo-wrap { text-align: center; margin-bottom: 3px; }
  .logo-wrap img { width: 30mm; max-height: 18mm; object-fit: contain; }
  .shop-tagline { font-size: 8px; text-align: center; letter-spacing: 0.6px; }
  .logo-wrap img { width: 30mm; max-height: 18mm; }
    .barcode-svg { height: 60px; min-height: 50px; }
  .shop-address { font-size: 9px; text-align: center; line-height: 1.3; }
  .shop-phone   { font-size: 9px; text-align: center; line-height: 1.3; }
  .divider-solid { border-top: 1px solid #000; margin: 3px 0; }
  .divider       { border-top: 1px dashed #000; margin: 3px 0; }
  table { width: 100%; border-collapse: collapse; }
  th, td { padding: 1px 2px; font-size: 10.5px; }
  th { font-weight: 700; }
  .header-row th { border-bottom: 1px solid #000; font-size: 10px; }
  .r { text-align: right; }
  .item-name { font-size: 10.5px; padding-top: 3px; font-weight: 500; }
  .item-detail-row { width: 100%; }
  .item-detail-row td { font-size: 10.5px; padding: 0 2px; }
  .col-header { display: flex; justify-content: space-between; font-size: 10px; }
  .summary-table td { padding: 1.5px 2px; font-size: 10.5px; }
  .summary-table .total-row td { font-weight: 700; font-size: 12px; }
  .balance-card { margin-top: 4px; padding: 4px 0 3px; text-align: center; border-top: 1px solid #000; border-bottom: 1px solid #000; }
  .balance-card.due { background: #f4f4f4; }
  .balance-card.change { background: #fff8e6; }
  .balance-label { font-size: 8.5px; letter-spacing: 0.5px; text-transform: uppercase; }
  .balance-value { font-size: 15px; font-weight: 700; line-height: 1.1; }
  .barcode-area { margin-top: 4px; text-align: center; }
  .barcode-svg { width: 100%; height: 60px; display: block; min-height: 50px; }
  .barcode-text { font-size: 8px; letter-spacing: 1px; margin-top: 2px; }
  .footer-text { font-size: 8.5px; text-align: center; margin-top: 2px; line-height: 1.35; }
  .terms { font-size: 8.5px; margin-top: 2px; line-height: 1.35; }
  @media print {
    @page { margin: 0; size: 72mm auto; }
    body { width: 72mm; }
  }
</style>
</head>
<body>

  <div class="receipt-header">
    ${shopName ? `<div class="shop-name">${shopName}</div>` : ''}
    ${shopAddr ? `<div class="shop-address">${shopAddr}</div>` : ''}
    ${shopPhone ? `<div class="shop-phone">Tel: ${shopPhone}</div>` : ''}
  </div>

  <div class="logo-wrap">
    <img src="data:image/jpeg;base64,${OSHINI_LOGO_B64}" alt="${shopName}" />
  </div>

  <div style="font-size:9.5px; text-align:center; margin-top:2px; font-weight:500;">
    Date ${invoiceDate}
  </div>
  <div style="font-size:9.5px; text-align:center; font-weight:500;">
    # ${invoiceNo}
  </div>
  ${cashier ? `<div style="font-size:9.5px; text-align:center; font-weight:500;">Cashier : ${cashier}</div>` : ''}
  ${customer ? `<div style="font-size:9.5px; text-align:center; font-weight:500;">Customer : ${customer}${custPhone ? '  ' + custPhone : ''}</div>` : ''}

  <div class="divider"></div>
  <div class="center bold" style="font-size:11px; font-weight:700;">Receipt - Original</div>
  <div class="divider"></div>

  <!-- Items header -->
  <table>
    <thead>
      <tr class="header-row">
        <th>#Item</th>
        <th class="r">Price</th>
        ${isReturnInvoice ? '' : '<th class="r">Save</th><th class="r">Net</th>'}
        <th class="r">Qty</th>
        <th class="r">Total</th>
      </tr>
    </thead>
  </table>

  <!-- Items body — two-row layout per item like original -->
  <table>
    <tbody>
      ${itemRows}
    </tbody>
  </table>

  <div class="divider-solid"></div>

  <!-- Summary -->
  <table class="summary-table">
    <tr>
      <td>Sub Total</td>
      <td class="r">${fmt(invoice.subtotal)}</td>
    </tr>
    ${isReturnInvoice ? '' : `<tr>
      <td>Total Discount</td>
      <td class="r">${fmt(invoice.discount)}</td>
    </tr>
    <tr>
      <td>Warranty</td>
      <td class="r">${warrantyText}</td>
    </tr>`}
    <tr class="total-row">
      <td>Total</td>
      <td class="r">${fmt(invoice.total)}</td>
    </tr>
    <tr>
      <td>Paid Cash</td>
      <td class="r">${fmt(invoice.paid_cash)}</td>
    </tr>
    <tr class="balance-row">
      <td>Balance</td>
      <td class="r">${balanceDisplay}</td>
    </tr>
  </table>

  ${outstandingSection}

  ${balance !== 0 ? `
  <div class="balance-card ${balance > 0 ? 'due' : 'change'}">
    <div class="balance-label">${balance > 0 ? 'Balance Due' : 'Change'}</div>
    <div class="balance-value">Rs. ${fmt(Math.abs(balance))}</div>
  </div>
  ` : ''}

  <!-- Barcode -->
  <div class="barcode-area">
    ${buildBarcodeSvg(invoiceNo)}
    <div class="barcode-text">${invoiceNo}</div>
  </div>

  <!-- Terms (Sinhala text as on original receipt — can be customized in shopConfig.terms) -->
  ${shop.terms ? `<div class="terms">${shop.terms}</div>` : `
  <div class="divider"></div>
  <div class="terms center" style="font-size:8px;">
    ${shop.footer || '*** Thank you for shopping with us ***'}
  </div>`}

</body>
</html>`;
}

async function printReceipt(invoice, shopConfig, printerName) {
  return new Promise((resolve) => {
    const tempFilePath = path.join(
      os.tmpdir(),
      `oshini-receipt-${Date.now()}-${Math.random().toString(36).slice(2)}.html`
    );

    const win = new BrowserWindow({
      show: false,
      webPreferences: {
        nodeIntegration: false,
        contextIsolation: true,
        backgroundThrottling: false,
      }
    });

    const html = buildReceiptHTML(invoice, shopConfig);
    fs.writeFileSync(tempFilePath, html, 'utf8');

    const cleanup = () => {
      try {
        if (fs.existsSync(tempFilePath)) fs.unlinkSync(tempFilePath);
      } catch (_) {
        // Ignore cleanup errors; the temp file lives in the system temp folder.
      }
    };

    win.on('closed', cleanup);

    win.loadFile(tempFilePath);

    win.webContents.once('did-finish-load', () => {
      win.webContents.executeJavaScript(`
        (async () => {
          if (document.fonts && document.fonts.ready) {
            try { await document.fonts.ready; } catch (_) {}
          }
          await new Promise((r) => requestAnimationFrame(() => requestAnimationFrame(r)));
        })();
      `).then(() => {
        const printOptions = {
          silent: true,
          printBackground: true,
          preferCSSPageSize: true,
          margins: { marginType: 'none' },
          pageSize: { width: 80000, height: 297000 },
        };

        if (printerName) printOptions.deviceName = printerName;

        win.webContents.print(printOptions, (success, err) => {
          cleanup();
          win.destroy();
          if (success) resolve({ success: true });
          else resolve({ success: false, error: err });
        });
      }).catch((err) => {
        cleanup();
        win.destroy();
        resolve({ success: false, error: err?.message || String(err) });
      });
    });

    win.webContents.once('did-fail-load', (_event, errorCode, errorDescription) => {
      cleanup();
      win.destroy();
      resolve({ success: false, error: `${errorCode}: ${errorDescription}` });
    });
  });
}

async function getAvailablePrinters(win) {
  return win.webContents.getPrintersAsync();
}

module.exports = { printReceipt, buildReceiptHTML, getAvailablePrinters };
